import math
from nltk.tokenize import word_tokenize
from collections import Counter

class LanguageModel:
    def __init__(self, train_data):
        self.train_data = train_data
        self.word_count = self.count_words(train_data)

    def count_words(self, data):
        word_count = Counter()
        for text in data:
            tokens = word_tokenize(text)
            word_count.update(tokens)
        return word_count

    def calculate_probability(self, word):
        return self.word_count[word] / len(self.train_data)

    def perplexity(self, test_data):
        total_loss = 0
        for text in test_data:
            tokens = word_tokenize(text)
            total_loss += -math.log(self.calculate_probability(tokens[0]), 2)
        return math.exp(total_loss / len(test_data))

